import { readFileSync, writeFileSync } from "fs";

const filePath = new URL("../artifacts/mobile/data/curriculum.ts", import.meta.url).pathname;
let content = readFileSync(filePath, "utf8");

function makeLesson(id, moduleId, title, description, contentText, xpReward, minutes, tags, practiceTask, quiz, buildChallenge) {
  return `      {
        id: "${id}",
        moduleId: "${moduleId}",
        title: "${title}",
        description: "${description}",
        content: ${JSON.stringify(contentText)},
        xpReward: ${xpReward},
        estimatedMinutes: ${minutes},
        tags: ${JSON.stringify(tags)},
        practiceTask: ${JSON.stringify(practiceTask)},
        quizQuestions: ${JSON.stringify(quiz, null, 8).replace(/^/gm, "        ").trimStart()},
        buildChallenge: ${JSON.stringify(buildChallenge, null, 8).replace(/^/gm, "        ").trimStart()},
      },`;
}

