for (const insertion of moduleInsertions) {
  const lessons = moduleLessons[insertion.moduleKey];
  if (!lessons) {
    if (!insertion.moduleKey) {
      continue;
    }
    console.error(`No lessons for ${insertion.moduleKey}`);
    continue;
  }

  const lessonBlock = lessons.join("\n");
  const newAnchor = insertion.anchor.replace(
    "    ],",
    lessonBlock + "\n    ],"
  );

  if (!content.includes(insertion.anchor)) {
    console.error(`Anchor not found for ${insertion.moduleKey}:`, JSON.stringify(insertion.anchor.slice(0, 100)));
    continue;
  }

  content = content.replace(insertion.anchor, newAnchor);
  console.log(`Inserted lessons for ${insertion.moduleKey}`);
}

